const sqlite3 = require('sqlite3').verbose();

const item = $input.first().json;

const signalMessageId = String(item.envelope?.timestamp || Date.now());
const testoOriginale = item.messageText || item.envelope?.dataMessage?.message || '';
const tipo = (item.attachments && item.attachments.length > 0) ? 'vocale' : 'testo';

await new Promise((resolve, reject) => {
  const db = new sqlite3.Database('/data/segretario.db');

  db.run(
    `INSERT OR IGNORE INTO messages_inbox 
     (signal_message_id, testo_originale, tipo, stato_elaborazione) 
     VALUES (?, ?, ?, 'ricevuto')`,
    [signalMessageId, testoOriginale, tipo],
    function(err) {
      db.close();
      if (err) reject(err);
      else resolve();
    }
  );
});

return [{
  json: {
    signal_message_id: signalMessageId,
    testo_originale: testoOriginale,
    tipo: tipo,
    mittente: item.envelope?.source || '',
    nome_mittente: item.sourceName || ''
  }
}];

