const response = $input.first().json;

// Estrai il testo dalla risposta Claude
const rawText = response.content[0].text;

// Parsa il JSON restituito da Alfred
const alfred = JSON.parse(rawText);

return [{
  json: {
    intent: alfred.intent,
    testo_risposta: alfred.testo_risposta,
    needs_confirmation: alfred.needs_confirmation,
    motivo_conferma: alfred.motivo_conferma || ''
  }
}];

const https = require('https');
const http = require('http');

const testo = $('Code in JavaScript1').item.json.testo_risposta;
const destinatario = $('Signal Trigger').item.json.envelope.sourceNumber;

const payload = JSON.stringify({
  message: testo,
  number: "+393517872627",
  recipients: [destinatario]
});

await new Promise((resolve, reject) => {
  const options = {
    hostname: 'segretario_signal_cli',
    port: 8080,
    path: '/v2/send',
    method: 'POST',
    headers: {
      'Content-Type': 'application/json',
      'Content-Length': Buffer.byteLength(payload)
    }
  };

  const req = http.request(options, (res) => {
    let data = '';
    res.on('data', chunk => data += chunk);
    res.on('end', () => {
      if (res.statusCode === 200 || res.statusCode === 201) {
        resolve(data);
      } else {
        reject(new Error(`Status ${res.statusCode}: ${data}`));
      }
    });
  });

  req.on('error', reject);
  req.write(payload);
  req.end();
});

return [{
  json: {
    messaggio_inviato: testo,
    destinatario: destinatario,
    stato: 'inviato'
  }
}];

const sqlite3 = require('sqlite3').verbose();

const inboxId = $('Code in JavaScript').item.json.signal_message_id;
const testoRisposta = $('Code in JavaScript1').item.json.testo_risposta;
const intent = $('Code in JavaScript1').item.json.intent;

await new Promise((resolve, reject) => {
  const db = new sqlite3.Database('/data/segretario.db');

  db.run(
    `INSERT INTO messages_outbox 
     (inbox_message_id, testo_risposta, tipo, azione_eseguita) 
     VALUES (?, ?, 'testo', ?)`,
    [inboxId, testoRisposta, intent],
    function(err) {
      db.close();
      if (err) reject(err);
      else resolve();
    }
  );
});

return [{
  json: {
    stato: 'completato',
    intent: intent,
    risposta_salvata: testoRisposta
  }
}];
